import java.util.Arrays;
public class ArrayReversal {
    // O(1) extra space: swap elements in-place
    static void reverseInPlace(int[] arr) {
        int lo = 0, hi = arr.length - 1;
        while (lo < hi) {
            int temp = arr[lo]; arr[lo] = arr[hi]; arr[hi] = temp;
            lo++; hi--;
        }
    }

    // O(n) extra space: create new reversed array
    static int[] reverseWithCopy(int[] arr) {
        int[] result = new int[arr.length]; // O(n) space!
        for (int i = 0; i < arr.length; i++)
            result[i] = arr[arr.length - 1 - i];
        return result;
    }

    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5};
        int[] copy = arr.clone();

        reverseInPlace(arr);
        int[] withCopy = reverseWithCopy(copy);

        System.out.println("In-place:   " + Arrays.toString(arr));
        System.out.println("With copy:  " + Arrays.toString(withCopy));
        System.out.println("Same result: " + Arrays.equals(arr, withCopy));
        System.out.println();
        System.out.println("In-place uses O(1) space — only 3 variables (lo, hi, temp)");
        System.out.println("Extra copy uses O(n) space — creates n-element result array");
        System.out.println("Both O(n) time. Choose based on: can we modify input?");
    }
}

