public class RecursionStack {
    static int maxDepth = 0, currentDepth = 0;

    // O(n) space: n+1 stack frames
    static void countDownRecursive(int n) {
        currentDepth++;
        maxDepth = Math.max(maxDepth, currentDepth);
        if (n >= 0) countDownRecursive(n - 1);
        currentDepth--;
    }

    // O(1) space: loop, no stack
    static void countDownIterative(int n) {
        while (n >= 0) n--;
    }

    public static void main(String[] args) {
        // Show O(n) stack depth:
        for (int n : new int[]{10, 100, 1000}) {
            maxDepth = 0; currentDepth = 0;
            countDownRecursive(n);
            System.out.printf("countDown(%d): max depth = %d → O(n) space%n", n, maxDepth);
        }
        System.out.println();
        System.out.println("Iterative version: O(1) space — no recursion stack");
        System.out.println("Rule: recursive depth = function input → space = O(input)");
        System.out.println();
        // Java default stack ≈ 500-1000 frames deep for int
        System.out.println("Java StackOverflowError: typically at depth ~5000-50000");
        System.out.println("For large n: prefer iterative (O(1) space) over recursive (O(n) space)");
    }
}

