import java.util.*;
public class FibTradeoff {
    // O(2ⁿ) time, O(n) space (recursion depth)
    static long fibNaive(int n) {
        if (n <= 1) return n;
        return fibNaive(n-1) + fibNaive(n-2);
    }

    // O(n) time, O(n) space (memo array)
    static long fibMemo(int n, long[] memo) {
        if (n <= 1) return n;
        if (memo[n] != 0) return memo[n];
        memo[n] = fibMemo(n-1, memo) + fibMemo(n-2, memo);
        return memo[n];
    }

    // O(n) time, O(1) space — best of both
    static long fibIterative(int n) {
        if (n <= 1) return n;
        long prev = 0, curr = 1;
        for (int i = 2; i <= n; i++) {
            long next = prev + curr;
            prev = curr; curr = next;
        }
        return curr;
    }

    public static void main(String[] args) {
        int n = 35;
        System.out.println("=== Fibonacci Trade-offs ===");

        long s = System.currentTimeMillis();
        long r1 = fibNaive(n);
        long t1 = System.currentTimeMillis() - s;

        s = System.currentTimeMillis();
        long r2 = fibMemo(n, new long[n+1]);
        long t2 = System.currentTimeMillis() - s;

        s = System.currentTimeMillis();
        long r3 = fibIterative(n);
        long t3 = System.currentTimeMillis() - s;

        System.out.println("fib(" + n + ") = " + r1);
        System.out.printf("Naive     O(2ⁿ) time, O(n) space:  %dms%n", t1);
        System.out.printf("Memoized  O(n)  time, O(n) space:  %dms%n", t2);
        System.out.printf("Iterative O(n)  time, O(1) space:  %dms%n", t3);
        System.out.println();
        System.out.println("All agree: " + (r1==r2 && r2==r3));
        System.out.println();
        System.out.println("Trade-off summary:");
        System.out.println("  Memoization: spend O(n) space to save O(2ⁿ) time → worth it!");
        System.out.println("  Iterative: O(n) time AND O(1) space → optimal solution");
        System.out.println("  Rule: iterative is usually better than memoized when order is clear");
    }
}

