import java.util.*;
public class DuplicateCheck {
    // O(n²) time, O(1) space
    static boolean nestedLoop(int[] arr) {
        for (int i = 0; i < arr.length; i++)
            for (int j = i+1; j < arr.length; j++)
                if (arr[i] == arr[j]) return true;
        return false;
    }

    // O(n) time, O(n) space
    static boolean hashSetCheck(int[] arr) {
        Set<Integer> seen = new HashSet<>(); // O(n) space
        for (int x : arr)
            if (!seen.add(x)) return true; // add() returns false if already present
        return false;
    }

    public static void main(String[] args) {
        int[] withDup = {3, 1, 4, 1, 5};
        int[] noDup = {1, 2, 3, 4, 5};

        System.out.println("=== Duplicate Check ===");
        System.out.println("nestedLoop has dup: " + nestedLoop(withDup) + " (expected true)");
        System.out.println("hashSetCheck has dup: " + hashSetCheck(withDup) + " (expected true)");
        System.out.println("Both agree: " + (nestedLoop(withDup)==hashSetCheck(withDup)));
        System.out.println();
        System.out.println("Trade-off:");
        System.out.println("  Nested loop: O(n²) time, O(1) extra space");
        System.out.println("  HashSet:     O(n) time,  O(n) extra space");
        System.out.println();
        System.out.println("When to choose which:");
        System.out.println("  Memory constrained (embedded, limited RAM): nested loop");
        System.out.println("  Performance priority (most cases): HashSet");
        System.out.println("  n > 10,000: HashSet is mandatory (n² unusable)");
    }
}

