import java.util.Arrays;
public class InPlaceOps {
    // O(n) time, O(1) space: two-pointer in-place
    static void removeZeros(int[] arr) {
        int writePos = 0; // position to write next non-zero
        // Pass 1: move all non-zeros to front
        for (int i = 0; i < arr.length; i++)
            if (arr[i] != 0) arr[writePos++] = arr[i];
        // Pass 2: fill remaining positions with zeros
        while (writePos < arr.length) arr[writePos++] = 0;
    }

    public static void main(String[] args) {
        int[] test1 = {0, 1, 0, 2, 3};
        int[] test2 = {0, 0, 0, 4, 5, 0, 6};
        int[] test3 = {1, 2, 3}; // no zeros

        removeZeros(test1);
        removeZeros(test2);
        removeZeros(test3);

        System.out.println("Test 1: " + Arrays.toString(test1)); // [1,2,3,0,0]
        System.out.println("Test 2: " + Arrays.toString(test2)); // [4,5,6,0,0,0,0]
        System.out.println("Test 3: " + Arrays.toString(test3)); // [1,2,3]
        System.out.println();
        System.out.println("Time: O(n) — two passes over n elements");
        System.out.println("Space: O(1) — only writePos variable, no extra array");
        System.out.println();
        System.out.println("Why O(1) space: we MODIFY the input array in-place.");
        System.out.println("No new array created. writePos is a single integer.");
    }
}

