import java.util.*;
public class PnLCache {
    record Trade(String merchantId, int amount) {}
    static final List<Trade> trades = new ArrayList<>();

    // O(n) per query: scan all trades
    static long computePnL(String merchantId) {
        long pnl = 0;
        for (Trade t : trades) // O(n) — n trades
            if (t.merchantId().equals(merchantId))
                pnl += t.amount();
        return pnl;
    }

    // Cache: O(n) first query, O(1) subsequent — O(m) space for m merchants
    static class CachedPnL {
        Map<String,Long> cache = new HashMap<>(); // O(m) space

        long get(String merchantId) {
            return cache.computeIfAbsent(merchantId, id -> computePnL(id)); // O(n) first time
            // Subsequent queries: O(1) HashMap lookup
        }
    }

    public static void main(String[] args) {
        // Setup: 10,000 trades for 100 merchants
        Random rand = new Random(42);
        for (int i = 0; i < 10000; i++)
            trades.add(new Trade("MRC-" + rand.nextInt(100), rand.nextInt(10000)-5000));

        CachedPnL cache = new CachedPnL();

        // Benchmark: 1000 queries for same 10 merchants
        String[] testMerchants = new String[10];
        for (int i = 0; i < 10; i++) testMerchants[i] = "MRC-" + i;

        long s = System.currentTimeMillis();
        for (int q = 0; q < 100; q++) for (String m : testMerchants) computePnL(m);
        long noCache = System.currentTimeMillis() - s;

        s = System.currentTimeMillis();
        for (int q = 0; q < 100; q++) for (String m : testMerchants) cache.get(m);
        long withCache = System.currentTimeMillis() - s;

        System.out.println("1000 PnL queries:");
        System.out.println("  No cache (O(n) each): " + noCache + "ms");
        System.out.println("  Cached (O(1) after first): " + withCache + "ms");
        System.out.println();
        System.out.println("Trade-off: O(m) space (100 cached values) → saves O(n×q) time");
        System.out.println("Cache space: 100 long values ≈ 800 bytes — negligible!");
        System.out.println("This is the caching/memoization trade-off in production systems.");
    }
}

