public class StringSpace {
    // O(n) space: creates StringBuilder (intermediate) + new String
    static String reverseNaive(String s) {
        return new StringBuilder(s).reverse().toString();
    }

    // O(n) space: must convert to char[] first (String is immutable!)
    // Note: truly O(1) extra space for strings is impossible in Java
    // because String is immutable — we must create char[]
    static String reverseInPlace(String s) {
        char[] chars = s.toCharArray(); // O(n) — unavoidable for String
        int lo = 0, hi = chars.length - 1;
        while (lo < hi) { char tmp=chars[lo];chars[lo]=chars[hi];chars[hi]=tmp;lo++;hi--; }
        return new String(chars);
    }

    // O(n) space: creates reversed string for comparison
    static boolean isPalindromeSpace(String s) {
        return s.equals(reverseNaive(s)); // O(n) extra space
    }

    // O(1) space: two pointers, no extra string
    static boolean isPalindromeO1(String s) {
        int lo = 0, hi = s.length() - 1;
        while (lo < hi) {
            if (s.charAt(lo) != s.charAt(hi)) return false;
            lo++; hi--;
        }
        return true; // O(1) extra space — just two int variables
    }

    public static void main(String[] args) {
        System.out.println("Reverse 'hello': " + reverseNaive("hello"));
        System.out.println("reverseNaive:    O(n) space (StringBuilder + new String)");
        System.out.println("reverseInPlace:  O(n) space (char[] — Java String immutability)");
        System.out.println();
        String[] tests = {"racecar","hello","madam","zerodha"};
        for (String t : tests) {
            boolean s1=isPalindromeSpace(t), s2=isPalindromeO1(t);
            System.out.println(t + ": space=" + s1 + ", O(1)=" + s2 + ", agree=" + (s1==s2));
        }
        System.out.println();
        System.out.println("isPalindromeO1: O(1) extra space — only lo and hi variables");
        System.out.println("Note: Java String.charAt() is O(1) — direct index access");
    }
}

