import java.util.*;
public class LinkedListReverse {
    static class Node { int val; Node next; Node(int v,Node n){val=v;next=n;} Node(int v){val=v;} }

    // O(n) space: copy to list, reverse, rebuild
    static Node reverseNaive(Node head) {
        List<Integer> vals = new ArrayList<>();
        for (Node cur=head; cur!=null; cur=cur.next) vals.add(cur.val);
        Collections.reverse(vals); // O(n) extra space
        Node dummy = new Node(0), cur = dummy;
        for (int v : vals) { cur.next = new Node(v); cur = cur.next; }
        return dummy.next;
    }

    // O(1) space: three-pointer reversal
    static Node reverseInPlace(Node head) {
        Node prev = null, cur = head, next;
        while (cur != null) {
            next = cur.next;  // save next
            cur.next = prev;  // reverse link
            prev = cur;       // advance prev
            cur = next;       // advance cur
        }
        return prev; // new head
    }

    static String toString(Node head) {
        StringBuilder sb = new StringBuilder();
        for (Node c=head; c!=null; c=c.next) sb.append(c.val).append(c.next!=null?"->": "");
        return sb.toString();
    }

    public static void main(String[] args) {
        Node list = new Node(1, new Node(2, new Node(3, new Node(4, new Node(5)))));
        System.out.println("Original:     " + toString(list));
        System.out.println("Naive O(n):   " + toString(reverseNaive(list)));

        list = new Node(1, new Node(2, new Node(3, new Node(4, new Node(5)))));
        System.out.println("InPlace O(1): " + toString(reverseInPlace(list)));

        System.out.println();
        System.out.println("Naive: O(n) time, O(n) space — creates ArrayList + new nodes");
        System.out.println("InPlace: O(n) time, O(1) space — only 3 pointer variables");
        System.out.println("Classic interview question: always use the O(1) space version!");
    }
}

