public class LCSSpace {
    // O(m×n) time AND space: full 2D table
    static int lcs2D(String a, String b) {
        int m=a.length(), n=b.length();
        int[][] dp = new int[m+1][n+1]; // O(m×n) space
        for (int i=1; i<=m; i++)
            for (int j=1; j<=n; j++)
                dp[i][j] = a.charAt(i-1)==b.charAt(j-1)
                    ? dp[i-1][j-1]+1
                    : Math.max(dp[i-1][j], dp[i][j-1]);
        return dp[m][n];
    }

    // O(m×n) time, O(n) space: only keep 2 rows
    static int lcsOptimized(String a, String b) {
        int m=a.length(), n=b.length();
        int[] prev=new int[n+1], curr=new int[n+1]; // O(n) space only!
        for (int i=1; i<=m; i++) {
            for (int j=1; j<=n; j++)
                curr[j] = a.charAt(i-1)==b.charAt(j-1)
                    ? prev[j-1]+1
                    : Math.max(prev[j], curr[j-1]);
            int[] tmp=prev; prev=curr; curr=tmp; // swap rows
        }
        return prev[n];
    }

    public static void main(String[] args) {
        String a="RAZORPAY", b="PAYTM";
        int r1=lcs2D(a,b), r2=lcsOptimized(a,b);
        System.out.println("LCS('" + a + "','" + b + "'):");
        System.out.println("  2D table:   " + r1 + " (O(m×n) space)");
        System.out.println("  Optimized:  " + r2 + " (O(n) space)");
        System.out.println("  Same result: " + (r1==r2));
        System.out.println();
        System.out.println("Space improvement: O(m×n) → O(n)");
        System.out.println("For m=n=1000: 1M cells → 1K cells = 1000x less memory!");
        System.out.println("This optimization is critical for large string DP in production.");
    }
}

