import java.util.*;
public class KthLargest {
    // O(n log n) time, O(1) space (in-place sort — sorts original array)
    static int kthLargestSort(int[] nums, int k) {
        Arrays.sort(nums);
        return nums[nums.length - k]; // kth largest is from end
    }

    // O(n log k) time, O(k) space — min-heap of size k
    static int kthLargestHeap(int[] nums, int k) {
        PriorityQueue<Integer> minHeap = new PriorityQueue<>(); // O(k) space
        for (int n : nums) {
            minHeap.offer(n);
            if (minHeap.size() > k) minHeap.poll(); // keep only k largest
        }
        return minHeap.peek(); // top of min-heap = kth largest
    }

    // O(n) average time, O(1) space — QuickSelect (partition-based)
    static int kthLargestQuickSelect(int[] nums, int k) {
        return quickSelect(nums.clone(), 0, nums.length-1, nums.length-k);
    }
    static int quickSelect(int[] arr, int lo, int hi, int targetIdx) {
        if (lo == hi) return arr[lo];
        int pivot = partition(arr, lo, hi);
        if (pivot == targetIdx) return arr[pivot];
        return pivot < targetIdx ? quickSelect(arr, pivot+1, hi, targetIdx)
                                 : quickSelect(arr, lo, pivot-1, targetIdx);
    }
    static int partition(int[] arr, int lo, int hi) {
        int pivot=arr[hi], i=lo;
        for (int j=lo; j<hi; j++) if(arr[j]<=pivot){int t=arr[i];arr[i]=arr[j];arr[j]=t;i++;}
        int t=arr[i];arr[i]=arr[hi];arr[hi]=t;
        return i;
    }

    public static void main(String[] args) {
        int[] nums={3,2,1,5,6,4}; int k=2;
        System.out.println("Array: " + Arrays.toString(nums) + ", k=" + k);
        System.out.println("Sort O(n log n)/O(1):    " + kthLargestSort(nums.clone(), k));
        System.out.println("Heap O(n log k)/O(k):    " + kthLargestHeap(nums, k));
        System.out.println("QuickSelect O(n)/O(1):   " + kthLargestQuickSelect(nums, k));
        System.out.println();
        System.out.println("All agree: " + (kthLargestSort(nums.clone(),k)==kthLargestHeap(nums,k)));
        System.out.println();
        System.out.println("Best for large n: QuickSelect O(n) time O(1) space (average)");
        System.out.println("Best for streaming: Min-heap O(log k) per element, O(k) space");
    }
}

