public class PalindromePartition {
    // O(n) space: create substrings to check
    static boolean naiveApproach(String s) {
        int lo=0, hi=s.length()-1;
        while (lo<hi) {
            if (s.charAt(lo)!=s.charAt(hi)) {
                // Try removing one character and check if remaining is palindrome
                String s1=s.substring(lo+1,hi+1); // O(n) space!
                String s2=s.substring(lo,hi);      // O(n) space!
                return isPalin(s1)||isPalin(s2);
            }
            lo++; hi--;
        }
        return true;
    }
    static boolean isPalin(String s){
        int l=0,r=s.length()-1; while(l<r){if(s.charAt(l)!=s.charAt(r))return false;l++;r--;}
        return true;
    }

    // O(1) space: no substrings, just check range with pointers
    static boolean optimalApproach(String s) {
        int lo=0, hi=s.length()-1;
        while (lo<hi) {
            if (s.charAt(lo)!=s.charAt(hi))
                return checkPalin(s,lo+1,hi)||checkPalin(s,lo,hi-1);
            lo++; hi--;
        }
        return true;
    }
    static boolean checkPalin(String s,int lo,int hi){
        while(lo<hi){if(s.charAt(lo)!=s.charAt(hi))return false;lo++;hi--;}
        return true;
    }

    public static void main(String[] args) {
        String[] tests={"raceacar","abca","abc","racecar","aba"};
        System.out.printf("%-15s %-10s %-10s%n","String","Naive","Optimal");
        System.out.println("-".repeat(35));
        for (String t:tests)
            System.out.printf("%-15s %-10s %-10s%n",t,naiveApproach(t),optimalApproach(t));
        System.out.println();
        System.out.println("Naive:   O(n) time per check, O(n) space (substring objects)");
        System.out.println("Optimal: O(n) time, O(1) space (only pointer variables)");
        System.out.println("Key: avoid creating substrings — pass range [lo, hi] instead");
    }
}

